exercises.solution:
def require_role(role):
    def decorator(func):
        def wrapper(*args, **kwargs):
            if args[0] == role:
                return func(*args, **kwargs)
            else:
                print("Access denied")
        return wrapper
    return decorator

@require_role("admin")
def delete_user(role, username):
    print(f"{username} deleted")

delete_user("admin", "bob")
delete_user("guest", "bob")

