class MyRange:
    def __init__(self, start, stop):
        self.start = start
        self.stop = stop
        self.current = start

    def __iter__(self):
        self.current = self.start
        return self

    def __next__(self):
        if self.current >= self.stop:
            raise StopIteration
        value = self.current
        self.current += 1
        return value

for num in MyRange(1, 6):
    print(num)

class Cycle:
    def __init__(self, data):
        self.data = data
        self.index = 0

    def __iter__(self):
        return self

    def __next__(self):
        if not self.data:
            raise StopIteration
        value = self.data[self.index % len(self.data)]
        self.index += 1
        return value

cycler = Cycle(['A', 'B', 'C'])
for _ in range(7):
    print(next(cycler))

