exercises.solution:
class Flatten:
    def __init__(self, list_of_lists):
        self.data = list_of_lists
        self.outer = 0
        self.inner = 0

    def __iter__(self):
        self.outer = 0
        self.inner = 0
        return self

    def __next__(self):
        while self.outer < len(self.data):
            if self.inner < len(self.data[self.outer]):
                value = self.data[self.outer][self.inner]
                self.inner += 1
                return value
            else:
                self.outer += 1
                self.inner = 0
        raise StopIteration

for item in Flatten([[1, 2], [3], [4, 5, 6]]):
    print(item)

